import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { booksAPI } from '../services/api';
import { useAuth } from '../context/AuthContext';
import { useToast } from '../context/ToastContext';
import BookFormModal from '../components/BookFormModal';
import './Dashboard.css';

export default function Dashboard() {
  const { user, isAdmin, getRole } = useAuth();
  const [books, setBooks]   = useState([]);
  const [loading, setLoading] = useState(true);
  const [showForm, setShowForm] = useState(false);
  const [editBook, setEditBook] = useState(null);
  const toast = useToast();

  const fetchBooks = async () => {
    setLoading(true);
    try {
      const res = await booksAPI.getAll();
      setBooks(res.data || []);
    } catch {
      toast.error('Failed to load books');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { fetchBooks(); }, []);

  const handleDelete = async (id) => {
    if (!window.confirm('Delete this book?')) return;
    try {
      await booksAPI.delete(id);
      toast.success('Book deleted');
      setBooks(prev => prev.filter(b => b.id !== id));
    } catch {
      toast.error('Delete failed');
    }
  };

  const handleFormSave = async (data) => {
    try {
      if (editBook) {
        await booksAPI.update(editBook.id, data);
        toast.success('Book updated');
      } else {
        await booksAPI.add(data);
        toast.success('Book added');
      }
      setShowForm(false);
      fetchBooks();
    } catch (err) {
      const msg = err.response?.data;
      toast.error(typeof msg === 'string' ? msg : 'Operation failed. Check you are logged in as Admin.');
    }
  };

  const role = getRole();

  // Stats for admin
  const stats = {
    total:    books.length,
    inStock:  books.filter(b => b.stock > 0).length,
    outStock: books.filter(b => b.stock === 0).length,
    avgPrice: books.length ? (books.reduce((s, b) => s + (b.price || 0), 0) / books.length).toFixed(2) : '0.00',
  };

  const categories = [...new Set(books.map(b => b.category).filter(Boolean))];

  return (
    <div className="dashboard-page">
      <div className="container">
        {/* Header */}
        <div className="dash-header fade-up">
          <div>
            <h1>
              {isAdmin() ? '🛡️ Admin Panel' : '👤 My Dashboard'}
            </h1>
            <p className="text-dim">
              Welcome back, <strong style={{ color: 'var(--gold)' }}>
                {user?.fullName || user?.email?.split('@')[0] || 'User'}
              </strong>
              <span className="badge badge-gold" style={{ marginLeft: 8 }}>{role}</span>
            </p>
          </div>
          {isAdmin() && (
            <button className="btn btn-gold" onClick={() => { setEditBook(null); setShowForm(true); }}>
              + Add Book
            </button>
          )}
        </div>

        {/* ── ADMIN VIEW ── */}
        {isAdmin() && (
          <>
            {/* Stats cards */}
            <div className="stats-grid fade-up">
              {[
                { label: 'Total Books',    value: stats.total,    icon: '📚', color: 'var(--gold)' },
                { label: 'In Stock',       value: stats.inStock,  icon: '✅', color: 'var(--green)' },
                { label: 'Out of Stock',   value: stats.outStock, icon: '❌', color: 'var(--red)' },
                { label: 'Avg Price (₹)',  value: stats.avgPrice, icon: '💰', color: 'var(--gold-light)' },
              ].map((s, i) => (
                <div key={i} className="stat-card card" style={{ animationDelay: `${i * 0.08}s` }}>
                  <div className="stat-card-icon">{s.icon}</div>
                  <div className="stat-card-value" style={{ color: s.color }}>{s.value}</div>
                  <div className="stat-card-label">{s.label}</div>
                </div>
              ))}
            </div>

            {/* Category breakdown */}
            {categories.length > 0 && (
              <div className="card dash-section fade-up">
                <h3 style={{ marginBottom: 'var(--gap-md)' }}>📊 Category Breakdown</h3>
                <div className="category-breakdown">
                  {categories.map(cat => {
                    const count = books.filter(b => b.category === cat).length;
                    const pct   = Math.round((count / books.length) * 100);
                    return (
                      <div key={cat} className="cat-row">
                        <span className="cat-name">{cat}</span>
                        <div className="cat-bar-wrap">
                          <div className="cat-bar" style={{ width: `${pct}%` }} />
                        </div>
                        <span className="cat-count">{count}</span>
                      </div>
                    );
                  })}
                </div>
              </div>
            )}

            {/* Book management table */}
            <div className="card dash-section fade-up">
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 'var(--gap-lg)' }}>
                <h3>📖 Manage Books</h3>
                <span className="text-dim text-sm">{books.length} total</span>
              </div>

              {loading ? (
                <div className="loading-wrap"><div className="spinner" /></div>
              ) : books.length === 0 ? (
                <div className="empty-state">
                  <div className="icon">📭</div>
                  <h3>No books yet</h3>
                  <p>Add your first book to get started</p>
                </div>
              ) : (
                <div className="table-wrap">
                  <table>
                    <thead>
                      <tr>
                        <th>#</th>
                        <th>Title</th>
                        <th>Author</th>
                        <th>Category</th>
                        <th>Price</th>
                        <th>Stock</th>
                        <th>Actions</th>
                      </tr>
                    </thead>
                    <tbody>
                      {books.map(book => (
                        <tr key={book.id}>
                          <td className="text-dim text-sm">#{book.id}</td>
                          <td>
                            <Link to={`/books/${book.id}`} style={{ color: 'var(--white)', fontWeight: 500 }}>
                              {book.title}
                            </Link>
                          </td>
                          <td className="text-dim">{book.author}</td>
                          <td>
                            <span className="badge badge-gold">{book.category || '—'}</span>
                          </td>
                          <td className="text-gold" style={{ fontWeight: 600 }}>₹{book.price?.toFixed(2)}</td>
                          <td>
                            <span style={{ color: book.stock > 0 ? 'var(--green)' : 'var(--red)', fontWeight: 500 }}>
                              {book.stock}
                            </span>
                          </td>
                          <td>
                            <div style={{ display: 'flex', gap: 6 }}>
                              <button
                                className="btn btn-ghost"
                                style={{ padding: '4px 10px', fontSize: 12 }}
                                onClick={() => { setEditBook(book); setShowForm(true); }}
                              >
                                Edit
                              </button>
                              <button
                                className="btn btn-danger"
                                style={{ padding: '4px 10px', fontSize: 12 }}
                                onClick={() => handleDelete(book.id)}
                              >
                                Del
                              </button>
                            </div>
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              )}
            </div>
          </>
        )}

        {/* ── USER VIEW ── */}
        {!isAdmin() && (
          <div className="user-dashboard fade-up">
            {/* Profile card */}
            <div className="card user-profile-card">
              <div className="profile-avatar">
                {(user?.fullName || user?.email || 'U')[0].toUpperCase()}
              </div>
              <div className="profile-details">
                <h2>{user?.fullName || 'BookNest User'}</h2>
                <p className="text-dim">{user?.email}</p>
                <span className="badge badge-gold" style={{ marginTop: 8 }}>
                  {role} Account
                </span>
              </div>
            </div>

            {/* Quick actions */}
            <div className="quick-actions">
              <h3 style={{ marginBottom: 'var(--gap-lg)' }}>Quick Actions</h3>
              <div className="action-cards">
                {[
                  { icon: '📚', title: 'Browse Catalog',  desc: 'Explore all available books',  to: '/books' },
                  { icon: '🔍', title: 'Search Books',    desc: 'Find books by title or author', to: '/books' },
                ].map((a, i) => (
                  <Link key={i} to={a.to} className="action-card card">
                    <div className="action-icon">{a.icon}</div>
                    <div>
                      <div className="action-title">{a.title}</div>
                      <div className="action-desc text-dim text-sm">{a.desc}</div>
                    </div>
                    <span className="action-arrow">→</span>
                  </Link>
                ))}
              </div>
            </div>

            {/* Recent books */}
            <div className="card dash-section">
              <h3 style={{ marginBottom: 'var(--gap-lg)' }}>📖 Recently Added Books</h3>
              {loading ? (
                <div className="loading-wrap"><div className="spinner" /></div>
              ) : (
                <div className="table-wrap">
                  <table>
                    <thead>
                      <tr>
                        <th>Title</th>
                        <th>Author</th>
                        <th>Category</th>
                        <th>Price</th>
                        <th>Status</th>
                      </tr>
                    </thead>
                    <tbody>
                      {books.slice(0, 8).map(book => (
                        <tr key={book.id}>
                          <td>
                            <Link to={`/books/${book.id}`} style={{ color: 'var(--white)', fontWeight: 500 }}>
                              {book.title}
                            </Link>
                          </td>
                          <td className="text-dim">{book.author}</td>
                          <td><span className="badge badge-gold">{book.category || '—'}</span></td>
                          <td className="text-gold" style={{ fontWeight: 600 }}>₹{book.price?.toFixed(2)}</td>
                          <td>
                            <span className={`badge ${book.stock > 0 ? 'badge-green' : 'badge-red'}`}>
                              {book.stock > 0 ? 'In Stock' : 'Out of Stock'}
                            </span>
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              )}
              <div style={{ marginTop: 'var(--gap-lg)', textAlign: 'center' }}>
                <Link to="/books" className="btn btn-outline">View All Books →</Link>
              </div>
            </div>
          </div>
        )}
      </div>

      {showForm && (
        <BookFormModal
          book={editBook}
          onSave={handleFormSave}
          onClose={() => setShowForm(false)}
        />
      )}
    </div>
  );
}
